        returns (Vm.Log[] memory)
    {
        uint256 count = 0;
        for (uint256 i = 0; i < logs.length; i++) {
            if (
                logs[i].topics[0]
                    == keccak256("LogMessagePublished(address,uint64,uint32,bytes,uint8)")
            ) {
                count += 1;
            }
        }

